def _seed_polity_ch74_notes_inner(conn, db_exec_fn, row_to_dict_fn, use_postgres, force=False):
    ph = "%s" if use_postgres else "?"
    existing = row_to_dict_fn(db_exec_fn(conn, f"SELECT id FROM study_notes WHERE topic={ph} AND chapter_num={ph}", ("Indian_Polity", 74)).fetchone() or {})
    if existing and not force: return
    if existing: db_exec_fn(conn, f"DELETE FROM study_notes WHERE topic={ph} AND chapter_num={ph}", ("Indian_Polity", 74))
    db_exec_fn(conn, f"INSERT INTO study_notes (subject,topic,chapter_num,title,content,summary) VALUES ({ph},{ph},{ph},{ph},{ph},{ph})",
        ("GK","Indian_Polity",74,"Chapter 71: Delimitation Commission",NOTES_HTML,SUMMARY_HTML))

def _seed_polity_ch74_mcqs_inner(conn, db_exec_fn, row_to_dict_fn, use_postgres, force=False):
    import datetime as _dt
    ph = "%s" if use_postgres else "?"
    _TOPIC = 'Indian_Polity'
    _CH = 74
    note_id = row_to_dict_fn(db_exec_fn(conn,
        f"SELECT id FROM study_notes WHERE topic={ph} AND chapter_num={ph}",
        (_TOPIC, _CH)).fetchone() or {}).get('id')
    if not note_id:
        return
    existing = list(db_exec_fn(conn,
        f"SELECT COUNT(*) FROM chapter_mcqs WHERE study_note_id={ph}",
        (note_id,)).fetchone() or [0])[0]
    if existing and not force:
        return
    if existing:
        db_exec_fn(conn, f"DELETE FROM chapter_mcqs WHERE study_note_id={ph}", (note_id,))
    now = _dt.datetime.utcnow().isoformat()
    for (sec, diff, q, a, b, c, d, ans, exp) in MCQ_DATA:
        db_exec_fn(conn,
            f"""INSERT INTO chapter_mcqs
                (study_note_id, section_idx, difficulty, exam_type,
                 q_te, opt_a, opt_b, opt_c, opt_d, correct, explanation_te, created_at)
                VALUES ({ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph})""",
            (note_id, sec, diff, 'General', q, a, b, c, d, ans, exp, now))
def seed_polity_ch74(conn, db_exec_fn, row_to_dict_fn, use_postgres=False, force=False):
    _seed_polity_ch74_notes_inner(conn, db_exec_fn, row_to_dict_fn, use_postgres, force)
    _seed_polity_ch74_mcqs_inner(conn, db_exec_fn, row_to_dict_fn, use_postgres, force)
